const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const thresholds = global.get('config')?.thresholds?.lightning || {};
const NEARBY_MILES             = thresholds.nearby_miles             ?? 5;
const DISTANT_COOLDOWN_MINUTES = thresholds.distant_cooldown_minutes ?? 5;
const NEARBY_AGE_OUT_MINUTES   = thresholds.nearby_age_out_minutes   ?? 10;

const p = msg.payload;
const distance = p.distance_miles;
const now = new Date();

// Always track the latest strike
flow.set('last_strike_distance', distance);
flow.set('last_strike_at', now.toISOString());

const lastNotifiedDistance = flow.get('last_notified_distance');
const lastNotifiedAt       = flow.get('last_notified_at');

// --- Notification decision ---
let shouldNotify = false;

if (lastNotifiedDistance === null || lastNotifiedDistance === undefined) {
    // First strike ever
    shouldNotify = true;

} else if (distance < NEARBY_MILES) {
    // Proximity mode — always notify
    shouldNotify = true;

} else if (distance < lastNotifiedDistance) {
    // Storm approaching
    shouldNotify = true;

} else {
    const elapsedMinutes = lastNotifiedAt
        ? (now.getTime() - new Date(lastNotifiedAt).getTime()) / 60000
        : Infinity;

    if (lastNotifiedDistance < NEARBY_MILES) {
        shouldNotify = elapsedMinutes >= NEARBY_AGE_OUT_MINUTES;
    } else {
        shouldNotify = elapsedMinutes >= DISTANT_COOLDOWN_MINUTES;
    }
}

if (shouldNotify) {
    flow.set('last_notified_distance', distance);
    flow.set('last_notified_at', now.toISOString());
}

msg.shouldNotify = shouldNotify;

node.status({
    fill:  distance < NEARBY_MILES ? 'red' : 'yellow',
    shape: 'dot',
    text:  formatStatus(`${distance} mi${shouldNotify ? ' — notified' : ' — suppressed'}`)
});

return msg;

const thresholds = global.get('config')?.thresholds?.lightning || {};
const NEARBY_MILES             = thresholds.nearby_miles             ?? 5;
const DISTANT_COOLDOWN_MINUTES = thresholds.distant_cooldown_minutes ?? 5;
const NEARBY_AGE_OUT_MINUTES   = thresholds.nearby_age_out_minutes   ?? 10;

const lastStrikeDistance = flow.get('last_strike_distance');
const lastStrikeAt       = flow.get('last_strike_at');

function deriveState(distance, strikeAt) {
    if (distance === null || distance === undefined) return 'Clear';
    const elapsedMinutes = (new Date().getTime() - new Date(strikeAt).getTime()) / 60000;
    if (distance < NEARBY_MILES && elapsedMinutes < NEARBY_AGE_OUT_MINUTES) return 'Nearby';
    if (distance >= NEARBY_MILES && elapsedMinutes < DISTANT_COOLDOWN_MINUTES) return 'Distant';
    return 'Clear';
}

const state = deriveState(lastStrikeDistance, lastStrikeAt);

const lastNotifiedDistance = flow.get('last_notified_distance');
const lastNotifiedAt       = flow.get('last_notified_at');

node.send([{
    topic:   'highland/state/weather/lightning',
    retain:  true,
    qos:     1,
    payload: JSON.stringify({
        timestamp:              new Date().toISOString(),
        source:                 'weather_lightning',
        state,
        last_strike_distance:   lastStrikeDistance   ?? null,
        last_strike_at:         lastStrikeAt         ?? null,
        last_notified_distance: lastNotifiedDistance ?? null,
        last_notified_at:       lastNotifiedAt       ?? null
    })
}, null]);

return [null, msg];

if (!msg.shouldNotify) return null;

const distance = flow.get('last_strike_distance');
const isNearby = flow.get('last_strike_distance') < (global.get('config')?.thresholds?.lightning?.nearby_miles ?? 5);

const title   = isNearby ? 'Lightning Nearby'    : 'Lightning Detected';
const message = isNearby
    ? `Lightning nearby \u2014 ${distance} miles away`
    : `Strike detected ${distance} miles away`;
const severity = isNearby ? 'high' : 'medium';

msg.payload = JSON.stringify({
    notification_id: 'weather.lightning',
    severity,
    source:         'weather_lightning',
    title,
    message,
    correlation_id: 'weather_lightning',
    url:            '/dashboard-weather/0',
    sticky:         true,
    group:          'weather_lightning'
});

msg.topic = 'highland/event/notify';
return msg;

const STATE_TOPIC = 'highland/state/weather/lightning';
const base        = 'homeassistant/sensor/highland_weather_lightning';

const device = {
    identifiers:  ['highland_weather_lightning'],
    name:         'Highland Weather Lightning',
    model:        'Tempest',
    manufacturer: 'Highland'
};

node.send({
    topic:   `${base}/lightning/config`,
    retain:  true,
    qos:     1,
    payload: JSON.stringify({
        name:                  'Weather Lightning',
        unique_id:             'highland_weather_lightning',
        state_topic:           STATE_TOPIC,
        value_template:        '{{ value_json.state }}',
        json_attributes_topic: STATE_TOPIC,
        icon:                  'mdi:weather-lightning',
        device
    })
});

return null;
